const input = $input.first().json;
const command = (input.command || '').trim();

if (!command) {
  throw new Error('No research query provided');
}

const params = input.parameters || {};

// Build search query from command + parameters
let searchQuery = command;
if (params.jurisdiction) searchQuery += ` ${params.jurisdiction}`;
if (params.year) searchQuery += ` ${params.year}`;

return [{
  json: {
    command: command,
    search_query: searchQuery,
    parameters: params,
    depth: params.depth || 'standard',
    execution_id: input.execution_id || $execution.id,
    timestamp: new Date().toISOString()
  }
}];

const input = $input.first().json;
const parsed = $('Parse Research Query').first().json;

// Extract and normalize search results
const rawResults = input.results || input.items || input.data || [];

const results = rawResults.slice(0, 10).map((r, i) => ({
  rank: i + 1,
  title: r.title || r.name || 'Untitled',
  url: r.url || r.link || '',
  snippet: r.snippet || r.description || r.abstract || '',
  source: r.source || r.domain || '',
  relevance_score: r.score || r.relevance || null
}));

// Filter out low-quality results
const filtered = results.filter(r => r.title && r.url);

return [{
  json: {
    command: parsed.command,
    search_query: parsed.search_query,
    parameters: parsed.parameters,
    results: filtered,
    result_count: filtered.length,
    depth: parsed.depth
  }
}];

