const startTime = new Date($('Parse Research Query').first().json.timestamp).getTime();
const input = $input.first().json;
const parsed = $('Parse Research Query').first().json;
const extracted = $('Extract Relevant Results').first().json;

let result = {};
let confidence = 0.5;

try {
  if (input.choices) {
    const synthesis = JSON.parse(input.choices[0].message.content);
    result = {
      summary: synthesis.summary,
      key_findings: synthesis.key_findings || [],
      citations: synthesis.citations || [],
      gaps: synthesis.gaps || [],
      sources_analyzed: extracted.result_count
    };
    confidence = synthesis.confidence_score || 0.5;
  } else {
    result = { raw_results: extracted.results, note: 'AI synthesis unavailable' };
    confidence = 0.3;
  }
} catch (e) {
  result = { raw_results: extracted.results, parse_error: e.message };
  confidence = 0.3;
}

// Downgrade confidence if few results found
if (extracted.result_count < 3) {
  confidence = Math.min(confidence, 0.5);
  result.gaps = result.gaps || [];
  result.gaps.push('Limited search results found');
}

const executionTime = Date.now() - startTime;

return [{
  json: {
    agent: '1002-agent-research',
    action: 'search',
    confidence: confidence,
    result: result,
    requires_approval: false,
    execution_time_ms: executionTime,
    execution_id: parsed.execution_id
  }
}];
